   323→func (s *Service) encryptSecrets(ctx context.Context, settings map[string]any) (map[string]any, error) {
   324→	result := deepCopyMap(settings)
   325→	configs := getConfigMaps(result)
   326→
   327→	for _, config := range configs {
   328→		for k, v := range config {
   329→			if IsSecretField(k) && v != "" {
   330→				strValue, ok := v.(string)
   331→				if !ok {
   332→					return result, fmt.Errorf("failed to encrypt %s setting because it is not a string: %v", k, v)
   333→				}
   334→
   335→				encryptedSecret, err := s.secrets.Encrypt(ctx, []byte(strValue), secrets.WithoutScope())
   336→				if err != nil {
   337→					return result, err
   338→				}
   339→				config[k] = base64.RawStdEncoding.EncodeToString(encryptedSecret)
   340→			}
   341→		}
   342→	}
   343→
   344→	return result, nil
   345→}
