   368→func (s *Service) doReload(ctx context.Context) {
   369→	s.logger.Debug("reloading SSO Settings for all providers")
   370→
   371→	settingsList, err := s.List(ctx)
   372→	if err != nil {
   373→		s.logger.Error("failed to fetch SSO Settings for all providers", "err", err)
   374→		return
   375→	}
   376→
   377→	for provider, connector := range s.reloadables {
   378→		settings := getSettingByProvider(provider, settingsList)
   379→
   380→		if settings == nil || len(settings.Settings) == 0 {
   381→			s.logger.Warn("SSO Settings is empty", "provider", provider)
   382→			continue
   383→		}
   384→
   385→		err = connector.Reload(ctx, *settings)
   386→		if err != nil {
   387→			s.metrics.reloadFailures.WithLabelValues(provider).Inc()
   388→			s.logger.Error("failed to reload SSO Settings", "provider", provider, "err", err)
   389→			continue
   390→		}
   391→	}
   392→}
