   256→		return nil
   257→	}
   258→
   259→	go s.reload(social, provider, *currentSettings)
   260→
   261→	return nil
   262→}
   263→
   264→func (s *Service) reload(reloadable ssosettings.Reloadable, provider string, currentSettings models.SSOSettings) {
   265→	err := reloadable.Reload(context.Background(), currentSettings)
   266→	if err != nil {
   267→		s.metrics.reloadFailures.WithLabelValues(provider).Inc()
   268→		s.logger.Error("failed to reload the provider", "provider", provider, "error", err)
   269→	}
   270→}
