   276→func (s *Service) RegisterReloadable(provider string, reloadable ssosettings.Reloadable) {
   277→	if s.reloadables == nil {
   278→		s.reloadables = make(map[string]ssosettings.Reloadable)
   279→	}
   280→	s.reloadables[provider] = reloadable
   281→}
